```class Solution {
    public int distinctSequences(int n) {
        int MOD = 1000000007;
        int[] dp = new int[n + 1];
        dp[0] = 1;
        for (int i = 1; i <= n; i++) {
            dp[i] = 0;
            for (int j = 1; j <= 6; j++) {
                if (i >= j) {
                    for (int k = 1; k <= 6; k++) {
                        if (k != j && gcd(j, k) == 1) {
                            dp[i] = (dp[i] + dp[i - j]) % MOD;
                        }
                    }
                }
            }
        }
        return dp[n];
    }
    int gcd(int a, int b) {
        return b == 0 ? a : gcd(b, a % b);
    }
}
